	ll query(int x, int y, const vector<ll>& sum, const vector<vector<int>>& g) {
		if (x == y) return 0;
		int l = lca(x, y);
		ll d = sum[x] + sum[y] - 2 * sum[l] + g[l].size();
		return d - g[x].size() - g[y].size();
	}

	ll query(int x, int y, const vector<vector<ll>>& dp) {
		int ox = x, oy = y;
		if (depth[x] < depth[y])swap(x, y);
		ll res = 0;
		for (int i = 29; i >= 0; i--)
			if (depth[x] - (1 << i) >= depth[y]) {
				res += dp[x][i];
				x = f[x][i];
			}
		if (x == y) {
			// x,y 都跳到了 lca，权值总和为 x + y - lca，这边把 lca 补上
			// 因为 dp[x][0] 存的 x 跳到父节点，但只拿了 x 的权值
			res += dp[x][0];
			return res - dp[ox][0] - dp[oy][0]; // 减掉原本两端点
		}
		for (int i = 29; i >= 0; i--) 
			if (f[x][i] != f[y][i]) {
				res += dp[x][i] + dp[y][i];
				x = f[x][i], y = f[y][i];
			}

		// x,y 再跳 2^0 就到 lca，所以这边缺了 x,y,lca 三个权值
		res += dp[x][0] + dp[y][0] + dp[f[x][0]][0];
		return res - dp[ox][0] - dp[oy][0]; // 减掉原本两端点
	}
