{
	int n, m; cin >> n >> m;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	bool ok = 0;
	fa(i, 1, n) {
		if (g[i].size() > 2) {
			ok = 1;
			break;
		}
	}
	if (!ok) {
		// 整个就是一条链，不可能有解
		fa(i, 1, m)cout << -1 << endl;
		return;
	}

	var lca = LCA(n, g);

	// 树上前缀和
	var sum = vector<ll>(n + 1, 0);
	var dfs = [&](var dfs, int now, int fa)->void {
		sum[now] = sum[fa] + g[now].size();
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
		}
		};
	dfs(dfs, 1, 0);

	// 树上倍增
	var dp = Vec2<ll>(n + 1, 31);
	fa(i, 1, n)dp[i][0] = g[i].size();
	fa(j, 1, 30)fa(i, 1, n) {
		dp[i][j] = dp[i][j - 1] + dp[lca.f[i][j - 1]][j - 1];
	}

	var dis = vector<int>(n + 1, INF);
	var Q = queue<pii>();
	fa(i, 1, n)if (g[i].size() > 2)dis[i] = 0, Q.push({ i, 0 });
	while (Q.size()) {
		var[now, d] = Q.front();
		Q.pop();
		if (d > dis[now])continue;
		for (int to : g[now]) {
			if (dis[to] > dis[now] + 1) {
				dis[to] = dis[now] + 1;
				Q.push({ to, dis[to] });
			}
		}
	}

	while (m--) {
		int x, y; cin >> x >> y;
		ll ans = LNF;
		ll d = lca.dis(x, y) - 1; // 算 (x,y) 最短路径间有多少节点
		ll qres = lca.query(x, y, dp);
		//ll qres = lca.query(x, y, sum, g);
		if (qres == 2 * d) // 所有节点的度数都为 2，说明 (x,y) 是条链
			cout << 2 * d + 4ll * min(dis[x], dis[y]) + 4 << endl;
		else // 中间有岔路，可以直接走
			cout << 2 * (d + 1) << endl;
	}
	return;
}
